#include <iostream>
#include <exception>
using namespace std;

// Base exception class
class CustomException : public exception {
protected:
 string msg;
public:
 CustomException(const string& m) : msg(m) {}
 const char* what() const noexcept override {
 return msg.c_str();
 }
};

// Derived exception classes
class DatabaseException : public CustomException {
public:
 DatabaseException(const string& m) : CustomException("Database: " + m) {}
};

class NetworkException : public CustomException {
public:
 NetworkException(const string& m) : CustomException("Network: " + m) {}
};

// Demonstration function
void processData(int choice) {
 if (choice == 1) throw DatabaseException("Connection failed");
 if (choice == 2) throw NetworkException("Timeout error");
 throw CustomException("Unknown error");
}

int main() {
 try {
 processData(1); // Try different values
 }
 // Order matters: derived classes first!
 catch (DatabaseException& e) {
 cout << "Caught Database Exception: " << e.what() << endl;
 }
 catch (NetworkException& e) {
 cout << "Caught Network Exception: " << e.what() << endl;
 }
 catch (CustomException& e) {
 cout << "Caught General Exception: " << e.what() << endl;
 }
 return 0;
}

#include <iostream>
using namespace std;

class Resource {
public:
 Resource() { cout << "Resource acquired\n"; }
 ~Resource() { cout << "Resource released\n"; }
};

class TestClass {
 Resource res; // Member object
public:
 TestClass() { 
 cout << "TestClass constructing...\n"; 
 throw "Error in constructor!"; // Throws exception
 }
 ~TestClass() { cout << "TestClass destroyed\n"; }
};

int main() {
 try {
 TestClass obj; // Constructor throws
 }
 catch (const char* e) {
 cout << "Caught: " << e << endl;
 cout << "Stack unwound - Resource released automatically\n";
 }
 return 0;
}

#include <iostream>
#include <vector>
using namespace std;

void logException(const exception& e) {
 cout << "LOG: Exception caught - " << e.what() << endl;
}

void innerFunction() {
 throw runtime_error("Original error");
}

void middleFunction() {
 try {
 innerFunction();
 }
 catch (runtime_error& e) {
 cout << "Middle: Handling partially - " << e.what() << endl;
 // Do some cleanup, then rethrow
 logException(e); // Log before rethrowing
 throw; // Rethrow the same exception
 }
}

int main() {
 try {
 middleFunction();
 }
 catch (runtime_error& e) {
 cout << "Main: Final handling - " << e.what() << endl;
 }
 return 0;
}

#include <iostream>
#include <string>
using namespace std;

// Nothrow guarantee - will never throw
int* createInt() noexcept {
 return new int(10);
}

// Strong guarantee - all or nothing
class StrongGuarantee {
 string data1, data2;
public:
 void setBoth(const string& a, const string& b) noexcept(false) {
 // Could throw, so implement strong guarantee
 string temp1 = a;
 string temp2 = b;
 // If second copy might throw, we should use copy-swap idiom
 data1 = temp1;
 data2 = temp2; // If this throws, data1 already changed!
 }
 // Better: use copy-swap for strong guarantee
 void setBothSafe(const string& a, const string& b) {
 StrongGuarantee temp;
 temp.data1 = a;
 temp.data2 = b;
 // Only swap if both copies succeeded
 swap(data1, temp.data1);
 swap(data2, temp.data2);
 }
};

// Basic guarantee - no resource leak
class BasicGuarantee {
 int* ptr;
public:
 BasicGuarantee() : ptr(nullptr) {}
 void allocate() {
 delete ptr; // Clean old
 ptr = new int[100]; // Might throw bad_alloc
 // Even if throws, basic guarantee: no leak
 }
 ~BasicGuarantee() { delete[] ptr; }
};

int main() {
 cout << "Testing exception safety guarantees" << endl;
 return 0;
}
